    function _unwrap(
        address from,
        address to,
        euint256 amount
    ) internal virtual returns (euint256) {
        require(to != address(0), ERC7984InvalidReceiver(to));
        require(
            from == msg.sender || isOperator(from, msg.sender),
            ERC7984UnauthorizedSpender(from, msg.sender)
        );
