        WrapAsPublicHandle,
        Add,
        Sub,
        Mul,
        Div,
        SafeAdd,
        SafeSub,
        SafeMul,
        SafeDiv,
        Select,
        Eq,
        Ne,
        Lt,
        Le,
        Gt,
        Ge,
        Transfer,
        Mint,
        Burn
