    function zeroHandle(TEEType teeType) internal view returns (bytes32) {
        return
            // [0]=version is implicitly 0x00
            (bytes32(bytes4(uint32(block.chainid))) >> (1 * 8)) |
            (bytes32(bytes1(uint8(teeType))) >> (5 * 8));
    }
